  }
  &.line-2 {
    -webkit-line-clamp: 2;
    white-space: normal;
  }
  &.line-3 {
    -webkit-line-clamp: 3;
    white-space: normal;
  }
}

.vh-space-loading {
  box-sizing: border-box;
  display: flex;
  align-items: center;
  justify-content: center;
  grid-column: span 3;
  width: 100%;
  height: 120px;
  &>span {
    background-color: var(--pixel-accent);
    width: 12px;
    height: 12px;
    margin: 4px;
    animation: vh-loading-animation .8s ease infinite;
    &:nth-of-type(1) { animation-delay: 0s; }
    &:nth-of-type(2) { animation-delay: .2s; }
    &:nth-of-type(3) { animation-delay: .4s; }
  }
}

@keyframes vh-loading-animation {
  0% { transform: scale(1); }
  50% { transform: scale(0.3); }
  100% { transform: scale(1); }
}

@keyframes vh-init-show {
  0% { transform: translateY(20px); opacity: 0; }
  100% { transform: translateY(0); opacity: 1; }
}

@keyframes blink-cursor {
  0%, 100% { opacity: 1; }
  50% { opacity: 0; }
}

@keyframes float {
  0%, 100% { transform: translateY(0px); }
  50% { transform: translateY(-12px); }
}

@keyframes pixel-bounce {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-4px); }
}

@keyframes scanline-move {
  0% { background-position: 0 0; }
  100% { background-position: 0 4px; }
}

.typewriter-cursor {
  color: var(--pixel-accent);
  animation: blink-cursor 0.8s step-end infinite;
}

.vh-animation.vh-animation-init {
  opacity: 0;
  animation: 300ms vh-init-show;
  animation-fill-mode: forwards;
}

@media screen and (max-width: 768px) {
  :root {
    --vh-aside-width: 0px;
  }
}

.article-base {
  display: flex;
  flex-direction: row;
  position: relative;

  .article-cover {
    width: 100%;
    flex-shrink: 0;
    overflow: hidden;
    border: 4px solid var(--pixel-dark);
    position: relative;

    @media (min-width: 768px) {
      width: 40%;
      max-width: 40%;
    }

    img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      image-rendering: pixelated;
      transition: transform 0.3s ease;
    }

    /* Bottom overlay badges */
    .cover-badges {
      position: absolute;
      bottom: 0;
      left: 0;
      right: 0;
      padding: 8px;
      display: flex;
      gap: 6px;
      background: linear-gradient(transparent, rgba(26,26,46,0.7));
    }

    /* Top-left pin/recommend badge */
    .top-badge {
      position: absolute;
      top: 0;
      left: 0;
      z-index: 2;
    }

    .pin-badge {
      display: inline-block;
      padding: 4px 10px;
      font-family: var(--pixel-font-title);
      font-size: 7px;
      color: #fff;
      background: var(--pixel-accent);
      border: 2px solid var(--pixel-dark);
      border-top: none;
      border-left: none;
      animation: pixel-bounce 1.5s ease-in-out infinite;
    }

    .recommend-badge {
      display: inline-block;
      padding: 4px 10px;
      font-family: var(--pixel-font-title);
      font-size: 7px;
      color: #fff;
      background: var(--pixel-secondary);
      border: 2px solid var(--pixel-dark);
      border-top: none;
      border-left: none;
    }
  }

  &:hover .article-cover img {
    transform: scale(1.05);
  }

  .article-info {
    flex: 1;
    padding: 1.25rem;
    display: flex;
    flex-direction: column;
    min-width: 0;
  }

  .article-category {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    margin-bottom: 0.5rem;
  }

  .article-meta-top {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.5rem;
    margin-bottom: 0.5rem;
    font-family: var(--pixel-font-title);
    font-size: 8px;
    color: var(--pixel-text-dim);
  }

  .article-title {
    font-family: var(--pixel-font-title);
    font-size: 11px;
    color: var(--pixel-accent);
    line-height: 1.6;
    margin-bottom: 0.75rem;
    transition: color var(--pixel-transition);
    a {
      color: inherit;
      border-bottom: none;
      &:hover {
        color: var(--pixel-accent);
      }
    }
    &:hover {
      color: var(--pixel-accent);
    }
  }

  .article-desc {
    font-size: 18px;
    color: var(--pixel-text-dim);
    line-height: 1.6;
    margin-bottom: 0.75rem;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }

  .article-meta {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    gap: 0.75rem;
    font-family: var(--pixel-font-title);
    font-size: 8px;
    color: var(--pixel-text-dim);
    span {
      display: inline-flex;
      align-items: center;
      gap: 4px;
    }
  }

  .article-bottom {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-top: auto;
    padding-top: 0.75rem;
  }

  .article-tags {
    display: flex;
    flex-wrap: wrap;
    gap: 0.4rem;
  }

  .article-read-btn {
    display: inline-block;
    padding: 4px 12px;
    font-family: var(--pixel-font-title);
    font-size: 8px;
    color: #fff;
    background: var(--pixel-blue);
    border: 3px solid var(--pixel-dark);
    box-shadow: 3px 3px 0px var(--pixel-dark);
    cursor: pointer;
    transition: all var(--pixel-transition);
    &:hover {
      transform: translate(-1px, -1px);
      box-shadow: 4px 4px 0px var(--pixel-dark);
    }
  }
}

@media screen and (max-width: 768px) {
  .article-base {
    flex-direction: column;
  }
}

.article-detail {
  .article-header {
    margin-bottom: 2rem;
    padding-bottom: 1.5rem;
    border-bottom: 4px dashed var(--pixel-dark);
    .article-title {
      font-family: var(--pixel-font-title);
      font-size: 20px;
      color: var(--pixel-accent);
      line-height: 1.6;
      margin-bottom: 1rem;
      word-break: break-word;
      text-shadow: 3px 3px 0px rgba(26,26,46,0.15);
    }
    .article-meta {
      display: flex;
      flex-wrap: wrap;
      gap: 1rem;
      font-family: var(--pixel-font-title);
      font-size: 9px;
      color: var(--pixel-text-dim);
      span {
        display: inline-flex;
        align-items: center;
        gap: 4px;
      }
    }
    .article-tags {
      display: flex;
      flex-wrap: wrap;
      gap: 0.5rem;
      margin-top: 1rem;
    }
  }

  .article-content {
    font-family: var(--pixel-font-body);
    font-size: 20px;
    line-height: 1.8;
    color: var(--pixel-text);
    word-break: break-word;

    h1, h2, h3, h4, h5, h6 {
      font-family: var(--pixel-font-title);
      color: var(--pixel-accent);
      margin: 2rem 0 1rem;
      line-height: 1.4;
    }
    h1 { font-size: 18px; }
    h2 {
      font-size: 14px;
      padding-bottom: 0.5rem;
      border-bottom: 4px solid var(--pixel-dark);
    }
    h3 { font-size: 12px; }
    h4 { font-size: 11px; }

    p { margin: 1rem 0; }

    a {
      color: var(--pixel-accent);
      border-bottom: 2px solid var(--pixel-accent);
      &:hover {
        color: var(--pixel-secondary);
        border-color: var(--pixel-secondary);
      }
    }

    img {
      max-width: 100%;
      border: 4px solid var(--pixel-dark);
      box-shadow: 6px 6px 0px var(--pixel-dark);
      image-rendering: pixelated;
    }

    blockquote {
      padding: 1rem 1.5rem;
      margin: 1.5rem 0;
      background: rgba(231,76,60,0.08);
      border-left: 4px solid var(--pixel-accent);
      border-top: 2px solid var(--pixel-dark);
      border-bottom: 2px solid var(--pixel-dark);
      border-right: 2px solid var(--pixel-dark);
      color: var(--pixel-text-dim);
    }

    code {
      font-family: var(--pixel-font-title) !important;
      font-size: 10px;
      padding: 2px 6px;
      background: var(--pixel-code-bg);
      border: 2px solid var(--pixel-dark);
      color: var(--pixel-code-color);
    }

    pre {
      padding: 1rem;
      margin: 1.5rem 0;
      background: var(--pixel-code-bg) !important;
      border: 4px solid var(--pixel-dark);
      box-shadow: 6px 6px 0px var(--pixel-dark);
      overflow-x: auto;
      code {
        padding: 0;
        background: none;
        border: none;
        font-size: 9px;
        color: var(--pixel-code-color);
      }
    }

    table {
      width: 100%;
      border: 4px solid var(--pixel-dark);
      margin: 1.5rem 0;
      th, td {
        padding: 10px;
        border: 2px solid var(--pixel-dark);
        font-family: var(--pixel-font-body);
        font-size: 18px;
      }
      th {
        background: var(--pixel-accent);
        color: #fff;
        font-family: var(--pixel-font-title);
        font-size: 9px;
      }
      tr:nth-child(even) {
        background: rgba(231,76,60,0.05);
      }
    }

    ul, ol {
      padding-left: 2rem;
      margin: 1rem 0;
      li {
        margin: 0.5rem 0;
        &::marker {
          font-family: var(--pixel-font-title);
          font-size: 10px;
        }
      }
    }

    hr {
      border: none;
      height: 3px;
      background: repeating-linear-gradient(90deg, var(--pixel-dark) 0, var(--pixel-dark) 8px, transparent 8px, transparent 16px);
      margin: 2rem 0;
    }
  }
}

.about-page {
  .about-header {
    text-align: center;
    margin-bottom: 2rem;
    padding-bottom: 1.5rem;
    border-bottom: 4px dashed var(--pixel-dark);
    .about-avatar {
      width: 96px;
      height: 96px;
      border: 4px solid var(--pixel-secondary);
      box-shadow: 6px 6px 0px var(--pixel-dark);
      image-rendering: pixelated;
      margin: 0 auto 1rem;
      position: relative;
    }
    .about-name {
      font-family: var(--pixel-font-title);
      font-size: 14px;
      color: var(--pixel-accent);
    }
    .about-motto {
      font-family: var(--pixel-font-body);
      font-size: 20px;
      color: var(--pixel-text-dim);
      margin-top: 0.5rem;
    }
  }
  .about-content {
    font-size: 20px;
    line-height: 1.8;
    color: var(--pixel-text);
    h1, h2, h3 {
      font-family: var(--pixel-font-title);
      color: var(--pixel-accent);
      margin: 1.5rem 0 0.75rem;
    }
    h1 { font-size: 14px; }
    h2 { font-size: 12px; }
    h3 { font-size: 10px; }
    p { margin: 1rem 0; }
    a {
      color: var(--pixel-accent);
      border-bottom: 2px solid;
      &:hover {
        color: var(--pixel-secondary);
      }
    }
  }
}
